    def positive_roots(self):
        """
        This method generates all the positive roots of
        A_n.  This is half of all of the roots of E_n;
        by multiplying all the positive roots by -1 we
        get the negative roots.

        Examples
        ========

        >>> from sympy.liealgebras.cartan_type import CartanType
        >>> c = CartanType("A3")
        >>> c.positive_roots()
        {1: [1, -1, 0, 0], 2: [1, 0, -1, 0], 3: [1, 0, 0, -1], 4: [0, 1, -1, 0],
                5: [0, 1, 0, -1], 6: [0, 0, 1, -1]}
        """
        n = self.n
        neghalf = Rational(-1, 2)
        poshalf = S.Half
        if n == 6:
            posroots = {}
            k = 0
            for i in range(n-1):
                for j in range(i+1, n-1):
                    k += 1
                    root = self.basic_root(i, j)
                    posroots[k] = root
                    k += 1
                    root = self.basic_root(i, j)
                    root[i] = 1
                    posroots[k] = root

            root = [poshalf, poshalf, poshalf, poshalf, poshalf,
                    neghalf, neghalf, poshalf]
            for a, b, c, d, e in itertools.product(
                    range(2), range(2), range(2), range(2), range(2)):
                if (a + b + c + d + e)%2 == 0:
                    k += 1
                    if a == 1:
                        root[0] = neghalf
                    if b == 1:
                        root[1] = neghalf
                    if c == 1:
                        root[2] = neghalf
                    if d == 1:
                        root[3] = neghalf
                    if e == 1:
                        root[4] = neghalf
                    posroots[k] = root[:]
            return posroots
        if n == 7:
            posroots = {}
            k = 0
            for i in range(n-1):
                for j in range(i+1, n-1):
                    k += 1
                    root = self.basic_root(i, j)
                    posroots[k] = root
                    k += 1
                    root = self.basic_root(i, j)
                    root[i] = 1
                    posroots[k] = root

            k += 1
            posroots[k] = [0, 0, 0, 0, 0, 1, 1, 0]
            root = [poshalf, poshalf, poshalf, poshalf, poshalf,
                    neghalf, neghalf, poshalf]
            for a, b, c, d, e, f in itertools.product(
                    range(2), range(2), range(2), range(2), range(2), range(2)):
                if (a + b + c + d + e + f)%2 == 0:
                    k += 1
                    if a == 1:
                        root[0] = neghalf
                    if b == 1:
                        root[1] = neghalf
                    if c == 1:
                        root[2] = neghalf
                    if d == 1:
                        root[3] = neghalf
                    if e == 1:
                        root[4] = neghalf
                    if f == 1:
                        root[5] = poshalf
                    posroots[k] = root[:]
            return posroots
        if n == 8:
            posroots = {}
            k = 0
            for i in range(n):
                for j in range(i+1, n):
                    k += 1
                    root = self.basic_root(i, j)
                    posroots[k] = root
                    k += 1
                    root = self.basic_root(i, j)
                    root[i] = 1
                    posroots[k] = root

            root = [poshalf, poshalf, poshalf, poshalf, poshalf,
                    neghalf, neghalf, poshalf]
            for a, b, c, d, e, f, g in itertools.product(
                    range(2), range(2), range(2), range(2), range(2),
                    range(2), range(2)):
                if (a + b + c + d + e + f + g)%2 == 0:
                    k += 1
                    if a == 1:
                        root[0] = neghalf
                    if b == 1:
                        root[1] = neghalf
                    if c == 1:
                        root[2] = neghalf
                    if d == 1:
                        root[3] = neghalf
                    if e == 1:
                        root[4] = neghalf
                    if f == 1:
                        root[5] = poshalf
                    if g == 1:
                        root[6] = poshalf
                    posroots[k] = root[:]
            return posroots



